#include<bits/stdc++.h>
using namespace std;
int main(){
	long double a,b,c,x1,x2;
	cin>>a>>b>>c;
	if((b*b-4*a*c)<0){
		cout<<"No answer!";
		return 0;
	}
	x1=(0-b+sqrtl(b*b-4*a*c))/(2*a);
	x2=(0-b-sqrtl(b*b-4*a*c))/(2*a);
	if(x1==x2){
		cout<<"x1=x2="<<fixed<<setprecision(5)<<x1;
	}else{
		if(x1>x2){
			cout<<"x1="<<fixed<<setprecision(5)<<x2<<";x2="<<fixed<<setprecision(5)<<x1;
		}else{
		cout<<"x1="<<fixed<<setprecision(5)<<x1<<";x2="<<fixed<<setprecision(5)<<x2;}
	}
	return 0;
}
